INSERT INTO jobs (job_code,title,department,type,deadline,posted_date,status,vacancies,min_experience,salary_scale,scope,description,requirements,responsibilities,created_by) VALUES
('TNC/PO/2026','Procurement Officer','Finance & Procurement','Full-Time','2026-02-28','2025-12-01','Closed',1,3,'Job Group L','county_wide','Manage procurement of goods, services and works in compliance with PPADA 2015.',"Bachelor's Degree in Procurement/Supply Chain Management\nMinimum 3 years relevant experience\nValid KISM membership\nComputer proficiency","Prepare and implement annual procurement plans\nManage tendering process\nMaintain supplier records\nEnsure PPADA 2015 compliance",1),
('TNC/ICT/2026','ICT Officer','ICT Department','Full-Time','2026-03-31','2026-03-01','Open',1,2,'Job Group K','county_wide','Support county ICT infrastructure, systems administration, network management and digital services.',"Bachelor's Degree in ICT or Computer Science\nMinimum 2 years experience\nCCNA preferred","Administer county servers and networks\nProvide technical support\nMaintain county digital platforms\nEnsure data security",1),
('TNC/FIN/2026','Finance Officer','Finance & Accounts','Full-Time','2026-03-31','2026-03-01','Open',2,3,'Job Group L','county_wide','Support financial management, budgeting, accounting and reporting per the PFM Act 2012.',"Bachelor's Degree in Finance or Accounting\nCPA(K) or ACCA\nMinimum 3 years experience\nIFMIS knowledge","Prepare financial statements\nManage budget implementation\nProcess payments\nCoordinate audits",1),
('TNC/HR/2026','Human Resource Officer','Public Service Management','Full-Time','2026-04-15','2026-03-10','Open',1,3,'Job Group L','county_wide','Manage county human resource functions including recruitment, welfare and performance management.',"Bachelor's Degree in Human Resource Management\nHigher Diploma in HRM\nMinimum 3 years experience\nIHRM membership","Coordinate recruitment processes\nMaintain personnel records\nImplement performance appraisal\nHandle staff welfare",1),
('TNC/LGL/2026','Legal Officer','County Attorney Office','Full-Time','2026-04-15','2026-03-10','Open',1,4,'Job Group M','county_wide','Provide legal advice and representation to the County Government on all legal matters.',"LLB Degree\nAdvocate of the High Court of Kenya\nMinimum 4 years post-admission experience\nLSK membership","Draft and review contracts\nRepresent county in legal proceedings\nAdvise on legal compliance\nPrepare legal opinions",1),
('TNC/AGR/2026','Agricultural Officer','Agriculture & Livestock','Full-Time','2026-04-30','2026-03-15','Open',3,2,'Job Group K','county_wide','Promote agricultural development and provide extension services across Trans Nzoia County.',"Bachelor's Degree in Agriculture\nMinimum 2 years experience\nProfessional registration","Provide agricultural extension services\nCoordinate development programmes\nConduct farmer training\nPrepare agricultural reports",1);
